const { spawnSync } = require('child_process');
const { q_b } = require('../b2/q');
const { k_c } = require('../c3/r');

function callNative(root, rev, primary, carry) {
  // Keep invocation as `cargo run` (a shim is provided under /app/tools/cargo).
  const env = { ...process.env, PATH: `${root}/tools:${process.env.PATH || ''}` };

  const proc = spawnSync(
    'cargo',
    ['run', '--quiet', '--bin', 'mhre_native', '--', rev, String(primary), String(carry)],
    { cwd: root, encoding: 'utf8', env }
  );
  if (proc.status !== 0) {
    throw new Error(proc.stderr || proc.stdout || proc.error?.message || 'native worker failed');
  }
  return Number(String(proc.stdout).trim());
}

function f_a(a, b, c) {
  let carry = 0;
  const rows = [];
  let acceptedOlder = true;
  let finalCounter = 0;

  const sumBases = a.cycles.reduce((acc, cycle) => acc + Number(cycle.base), 0);

  for (let index = 0; index < a.cycles.length; index += 1) {
    const cycle = a.cycles[index];

    const deferred = q_b(cycle.deferred || [], index, c);
    const factor = k_c(cycle.dep, index, c);

    const nativeValue = callNative(b, cycle.native, cycle.base, carry);

    // Older markers must normalize like newer ones; if they don't, mark unaccepted.
    if (cycle.native === 'old' && nativeValue !== Number(cycle.base) + carry) {
      acceptedOlder = false;
    }

    const rowValue = nativeValue + factor + deferred.reduce((acc, value) => acc + value, 0);

    rows.push({ index, value: rowValue, factor, nativeValue, deferred });

    // Each cycle's native row feeds the next.
    carry = nativeValue;
    finalCounter = nativeValue;
  }

  const dependencyTotal = rows.reduce((acc, row) => acc + row.factor, 0);
  const healthy = acceptedOlder && finalCounter === sumBases;

  return {
    name: a.name,
    rows,
    finalCounter,
    dependencyTotal,
    acceptedOlder,
    healthy
  };
}

